		const detailsBlob = {
			_type: { name: 'MailDetailsBlob' },
			_id: ['detailsListId', 'detailsElementId'],
			details: { body: { text: 'encrypted' } },
		}

		// The bug is that these two happen:
		// 1. mailSessionKey = resolveSessionKey(Mail) -> returns key
		// 2. caching happens in .then() -> setSessionKeyCacheWithTuple(mailDetails, key)
		//
		// But when loadMultiple() is called for MailDetailsBlob, it calls:
		// 3. detailsSessionKey = resolveSessionKey(MailDetailsBlob) -> looks in cache
		//    -> NOT FOUND because .then() from step 1 hasn't executed yet
		//
		// This is an async timing issue

		let cachePopulated = false

		// Simulate async caching
		const cachePromise = Promise.resolve().then(() => {
			cachePopulated = true
			sessionKeyCache['detailsElementId'] = new Uint8Array(16)
		})

		// Try to resolve immediately (before cache is populated)
		expect(cachePopulated).toBe(false) // Cache not populated yet
		expect(sessionKeyCache['detailsElementId']).toBeUndefined() // Session key not in cache

		// This is why MailDetailsBlob cannot find its session key
		expect(() => {
			mockResolveSessionKey(
				{ name: 'MailDetailsBlob', app: 'tutanota', encrypted: true },
				detailsBlob
			)
		}).toThrow(/could not resolve session key/)

		// Cache will be populated after the promise resolves
		return cachePromise.then(() => {
			expect(cachePopulated).toBe(true)
			// But by then, it's too late - MailDetailsBlob resolution already failed
		})
	})
